// // This module implements a 2-to-1 multiplexer with parameterized input sizes. When the select signal is high, the output will be equal to in1; when the select signal is low, the output will be equal to in2.
module top_module(in1, in2, out, select);parameter size = 1;
	input[size-1:0] in1, in2;
	output[size-1:0] out;
	input select;
	assign out = select? in2 : in1;
endmodule
